#[derive(Clone)]
#[php_class]
#[php(name = "Spikard\\Php\\App")]
pub struct App {
    inner: Arc<std::sync::Mutex<spikard::App>>,
}

#[php_impl]
impl App {
    /**
     * Attach an existing Axum router to this application, returning ownership.
     */
    pub fn merge_axum_router(&self, router: String) -> App {
        Self {
            inner: Arc::new(std::sync::Mutex::new(
                self.inner.lock().unwrap().merge_axum_router(router),
            )),
        }
    }

    /**
     * Attach an Axum router using a mutable reference for incremental configuration.
     */
    pub fn attach_axum_router(&self, router: String) -> App {
        Self {
            inner: Arc::new(std::sync::Mutex::new(
                self.inner.lock().unwrap().attach_axum_router(router).clone(),
            )),
        }
    }

    /**
     * Build the underlying Axum router.
     * @throws SpikardException Returns an error if server or router construction fails.
     */
    pub fn into_router(&self) -> PhpResult<String> {
        let result = self
            .inner
            .lock()
            .unwrap()
            .into_router()
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(result)
    }

    /**
     * Decompose the application into its Axum router and server configuration.
     *
     * This is the low-level escape hatch used by the C FFI layer to start the
     * server on a background thread while retaining the bind address from the
     * caller-supplied `ServerConfig`.  Prefer `App.run` for normal use.
     * @throws SpikardException Returns an error if router construction fails.
     */
    pub fn into_router_and_config(&self) -> PhpResult<String> {
        let result = self
            .inner
            .lock()
            .unwrap()
            .into_router_and_config()
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(result)
    }

    /**
     * Create a new application with the default server configuration.
     */
    #[php(name = "new")]
    pub fn new() -> App {
        Self {
            inner: Arc::new(std::sync::Mutex::new(spikard::App::new())),
        }
    }

    #[allow(clippy::should_implement_trait)]
    #[php(name = "default")]
    pub fn default() -> App {
        Self {
            inner: Arc::new(std::sync::Mutex::new(spikard::App::default())),
        }
    }
}

impl Default for App {
    fn default() -> Self {
        Self::new()
    }
}

