#[derive(Clone, serde::Serialize, serde::Deserialize, Default)]
#[php_class]
#[php(name = "Spikard\\Php\\ResponseSnapshot")]
#[serde(default, rename_all = "camelCase")]
pub struct ResponseSnapshot {
    /// HTTP status code.
    #[php(prop, name = "status")]
    pub status: u16,
    /// Response headers (lowercase keys for predictable lookups).
    pub headers: HashMap<String, String>,
    /// Response body bytes (decoded for supported encodings).
    pub body: Vec<u8>,
}

#[php_impl]
impl ResponseSnapshot {
    #[php(name = "from_json")]
    pub fn from_json(json: String) -> PhpResult<Self> {
        serde_json::from_str(&json).map_err(|e| PhpException::default(e.to_string()))
    }

    #[php(constructor)]
    pub fn new(status: u16, body: PhpBytes) -> Self {
        Self {
            status,
            headers: Default::default(),
            body: body.0,
        }
    }

    pub fn get_status(&self) -> u16 {
        self.status.clone()
    }

    pub fn get_headers(&self) -> HashMap<String, String> {
        self.headers.clone()
    }

    pub fn get_body(&self) -> Vec<u8> {
        self.body.clone()
    }

    pub fn text(&self) -> PhpResult<String> {
        let core_self = spikard_http::ResponseSnapshot {
            status: self.status,
            headers: self.headers.clone().into_iter().collect(),
            body: self.body.clone().into(),
        };
        let result = core_self
            .text()
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(result)
    }

    pub fn header(&self, name: String) -> Option<String> {
        let core_self = spikard_http::ResponseSnapshot {
            status: self.status,
            headers: self.headers.clone().into_iter().collect(),
            body: self.body.clone().into(),
        };
        core_self.header(&name).map(Into::into)
    }
}

