/// Convert a `spikard::AppError` error to a PHP exception.
#[allow(dead_code)]
fn app_error_to_php_err(e: spikard::AppError) -> ext_php_rs::exception::PhpException {
    let msg = e.to_string();
    #[allow(unreachable_patterns)]
    match &e {
        spikard::AppError::Route(..) => ext_php_rs::exception::PhpException::default(format!("[Route] {}", msg)),
        spikard::AppError::Server(..) => ext_php_rs::exception::PhpException::default(format!("[Server] {}", msg)),
        spikard::AppError::Decode(..) => ext_php_rs::exception::PhpException::default(format!("[Decode] {}", msg)),
        _ => ext_php_rs::exception::PhpException::default(msg),
    }
}

